#[test]
fn test_real_data_mock_prover() {
    let fixtures = discover_fixtures();
    if fixtures.is_empty() {
        println!("No fixture files found in tests/fixtures/ — skipping test.");
        println!("Run dex-circuit-data-exporter to generate fixtures.");
        return;
    }

    let params = base_circuit_params();

    for fixture_path in &fixtures {
        let filename = fixture_path.file_name().unwrap().to_str().unwrap();
        println!("\n========== MockProver: {} ==========", filename);

        let json = load_fixture(fixture_path);
        println!("  Description: {}", json.description);
        println!("  Chain steps: {}", json.num_active_chain_steps);

        let parsed = parse_fixture(&json);
        let ephemeral_pubkey = Fr::from(0xDEADu64);
        let mut instances = compute_instances(&parsed);
        instances.push(ephemeral_pubkey);

        println!(
            "  Expected instances: poseidon={}, final_root={}",
            hex::encode(instances[0].to_repr()),
            hex::encode(instances[1].to_repr()),
        );

        let circuit = DarkDexCircuitNew::new(
            parsed.sk_u,
            ephemeral_pubkey,
            parsed.entries,
            parsed.events_proof_siblings,
            parsed.events_proof_position,
            parsed.account_dapp_id,
            parsed.account_id,
            parsed.block_id,
            parsed.envelope_hash_bytes,
            parsed.block_proof_siblings,
            parsed.block_proof_position,
            parsed.dense_chain,
            parsed.num_active_chain_steps,
            params.clone(),
        );

        println!("  Running MockProver...");
        let prover = MockProver::<Fr>::run(K, &circuit, vec![instances]).unwrap();
        match prover.verify() {
            Ok(()) => println!("  {} PASSED", filename),
            Err(errors) => {
                println!("  {} FAILED with {} errors:", filename, errors.len());
                for (i, err) in errors.iter().enumerate().take(30) {
                    println!("    Error {}: {}", i, err);
                }
                panic!("MockProver failed for {}", filename);
            }
        }
    }

    println!("\nAll {} fixture(s) passed MockProver!", fixtures.len());
}

#[test]
fn test_real_data_real_prover() {
    use halo2_base::halo2_proofs::plonk::{keygen_pk, keygen_vk};
    use halo2_base::utils::fs::gen_srs;
    use halo2_base::utils::testing::{check_proof_with_instances, gen_proof_with_instances};
    use std::time::Instant;

    let fixtures = discover_fixtures();
    if fixtures.is_empty() {
        println!("No fixture files found in tests/fixtures/ — skipping test.");
        println!("Run dex-circuit-data-exporter to generate fixtures.");
        return;
    }

    println!("Found {} fixture(s)", fixtures.len());

    let params = base_circuit_params();

    // Step 1: Keygen from the first fixture
    let first_json = load_fixture(&fixtures[0]);
    let first_parsed = parse_fixture(&first_json);

    let ephemeral_pubkey = Fr::from(0xDEADu64);
    let keygen_circuit = DarkDexCircuitNew::new(
        first_parsed.sk_u,
        ephemeral_pubkey,
        first_parsed.entries,
        first_parsed.events_proof_siblings,
        first_parsed.events_proof_position,
        first_parsed.account_dapp_id,
        first_parsed.account_id,
        first_parsed.block_id,
        first_parsed.envelope_hash_bytes,
        first_parsed.block_proof_siblings,
        first_parsed.block_proof_position,
        first_parsed.dense_chain,
        first_parsed.num_active_chain_steps,
        params.clone(),
    );

    println!("Generating SRS (K={})...", K);
    let srs = gen_srs(K);

    let start = Instant::now();
    let vk = keygen_vk(&srs, &keygen_circuit).expect("keygen_vk failed");
    println!("keygen_vk: {:?}", start.elapsed());

    let start = Instant::now();
    let pk = keygen_pk(&srs, vk, &keygen_circuit).expect("keygen_pk failed");
    println!("keygen_pk: {:?}", start.elapsed());

    let break_points = keygen_circuit.base_circuit_builder.borrow().break_points();

    // Step 2: Prove each fixture with the shared VK/PK
    struct ProofResult {
        filename: String,
        chain_steps: usize,
        prove_ms: u128,
        verify_ms: u128,
        proof_size: usize,
    }
    let mut results: Vec<ProofResult> = Vec::new();

    for fixture_path in &fixtures {
        let filename = fixture_path
            .file_name()
            .unwrap()
            .to_str()
            .unwrap()
            .to_string();
        println!("\n========== Real proof: {} ==========", filename);

        let json = load_fixture(fixture_path);
        println!("  Description: {}", json.description);
        let chain_steps = json.num_active_chain_steps;

        let parsed = parse_fixture(&json);
        let mut instances = compute_instances(&parsed);
        instances.push(ephemeral_pubkey);

        let prover_circuit = DarkDexCircuitNew::new_for_proving(
            parsed.sk_u,
            ephemeral_pubkey,
            parsed.entries,
            parsed.events_proof_siblings,
            parsed.events_proof_position,
            parsed.account_dapp_id,
            parsed.account_id,
            parsed.block_id,
            parsed.envelope_hash_bytes,
            parsed.block_proof_siblings,
            parsed.block_proof_position,
            parsed.dense_chain,
            parsed.num_active_chain_steps,
            params.clone(),
            break_points.clone(),
        );

        let start = Instant::now();
        let proof_bytes =
            gen_proof_with_instances(&srs, &pk, prover_circuit, &[&instances]);
        let prove_ms = start.elapsed().as_millis();
        println!("  Proof generation: {}ms ({} bytes)", prove_ms, proof_bytes.len());

        let start = Instant::now();
        check_proof_with_instances(&srs, pk.get_vk(), &proof_bytes, &[&instances], true);
        let verify_ms = start.elapsed().as_millis();
        println!("  Proof verification: {}ms", verify_ms);
        println!("  {} PASSED", filename);

        results.push(ProofResult {
            filename,
            chain_steps,
            prove_ms,
            verify_ms,
            proof_size: proof_bytes.len(),
        });
    }

    // Print summary table
    println!("\n╔════════════════════════════════════════════╤════════╤══════════╤══════════╤════════════╗");
    println!("║ fixture                                    │ steps  │  prove   │  verify  │ proof_size ║");
    println!("╠════════════════════════════════════════════╪════════╪══════════╪══════════╪════════════╣");
    for r in &results {
        println!(
            "║ {:<42} │   {:>2}   │ {:>6}ms │ {:>6}ms │   {:>6}B  ║",
            r.filename, r.chain_steps, r.prove_ms, r.verify_ms, r.proof_size,
        );
    }
    println!("╚════════════════════════════════════════════╧════════╧══════════╧══════════╧════════════╝");
    println!(
        "\nAll {} fixture(s) passed with shared VK/PK!",
        results.len()
    );
}


#[test]
fn test_debug_fixture_native() {
    let fixtures = discover_fixtures();
    if fixtures.is_empty() {
        println!("No fixtures found — skipping.");
        return;
    }

    let fixture_path = &fixtures[0];
    let filename = fixture_path.file_name().unwrap().to_str().unwrap();
    println!("\n========== Debug: {} ==========", filename);

    let json = load_fixture(fixture_path);
    let parsed = parse_fixture(&json);

    // 1. Verify BOC: SHA-256 of cell_repr_data should match repr_hash
    use sha2::{Sha256, Digest};
    let mut hasher = Sha256::new();
    hasher.update(&parsed.entries[0].cell_repr_data);
    let root_sha256: [u8; 32] = hasher.finalize().into();
    println!("  Root repr_hash from BOC: {}", hex::encode(&parsed.entries[0].repr_hash));
    println!("  Root SHA-256 of cell_repr_data: {}", hex::encode(&root_sha256));
    assert_eq!(root_sha256, parsed.entries[0].repr_hash, "Root SHA-256 mismatch!");

    let mut hasher = Sha256::new();
    hasher.update(&parsed.entries[1].cell_repr_data);
    let child_sha256: [u8; 32] = hasher.finalize().into();
    println!("  Child repr_hash from BOC: {}", hex::encode(&parsed.entries[1].repr_hash));
    println!("  Child SHA-256 of cell_repr_data: {}", hex::encode(&child_sha256));
    assert_eq!(child_sha256, parsed.entries[1].repr_hash, "Child SHA-256 mismatch!");

    // 2. Verify child hash is embedded in root cell
    let offset = parsed.entries[0].childs_repr_hashes_offset.as_ref().unwrap()[0] as usize;
    let embedded_hash = &parsed.entries[0].cell_repr_data[offset..offset+32];
    println!("  Child hash embedded in root at offset {}: {}", offset, hex::encode(embedded_hash));
    assert_eq!(embedded_hash, &parsed.entries[1].repr_hash, "Embedded child hash mismatch!");

    // 3. Check repr_hash_fr packing
    let repr_hash_fr = bytes_to_fr(&parsed.entries[0].repr_hash);
    println!("  repr_hash_fr (LE packed): {}", hex::encode(fr_to_bytes(repr_hash_fr)));

    // 4. Check ext_msg_leaf
    let ext_msg_leaf = poseidon_hash_96_native(
        &parsed.account_dapp_id,
        &parsed.account_id,
        &parsed.entries[0].repr_hash,
    );
    println!("  ext_msg_leaf: {}", hex::encode(&ext_msg_leaf));

    // 5. Check events root (should equal ext_msg_leaf for depth 0)
    let ext_out_root = if parsed.events_proof_siblings.is_empty() {
        println!("  Events depth = 0, ext_out_root = ext_msg_leaf");
        ext_msg_leaf
    } else {
        let events_proof = preprocess_dense_proof(
            ext_msg_leaf,
            &parsed.events_proof_siblings,
            parsed.events_proof_position,
        );
        let root = fr_to_bytes(compute_root_native(&events_proof));
        println!("  Events root: {}", hex::encode(&root));
        root
    };

    // 6. Check block_leaf
    let block_leaf = poseidon_hash_96_native(
        &parsed.block_id,
        &parsed.envelope_hash_bytes,
        &ext_out_root,
    );
    println!("  block_leaf: {}", hex::encode(&block_leaf));

    // 7. Check block root (root_1)
    let block_proof = preprocess_dense_proof(
        block_leaf,
        &parsed.block_proof_siblings,
        parsed.block_proof_position,
    );
    let root_1_fr = compute_root_native(&block_proof);
    let root_1_bytes = fr_to_bytes(root_1_fr);
    println!("  root_1 (block tree root): {}", hex::encode(&root_1_bytes));

    // 8. Check chain padding
    let num_active = parsed.num_active_chain_steps;
    println!("  Active chain steps: {}", num_active);
    println!("  Chain length: {}", parsed.dense_chain.len());
    for (i, link) in parsed.dense_chain.iter().enumerate().take(3) {
        println!("    chain[{}]: active={}, leaf={}, depth={}", 
                 i, link.active, hex::encode(&link.leaf_native), link.siblings.len());
    }

    // 9. Verify chain padding leaf matches root_1 (for T=0)
    if num_active == 0 {
        let padding_leaf = &parsed.dense_chain[0].leaf_native;
        println!("  Padding leaf:     {}", hex::encode(padding_leaf));
        println!("  Expected (root_1): {}", hex::encode(&root_1_bytes));
        assert_eq!(padding_leaf, &root_1_bytes, "Padding leaf should equal root_1 for T=0!");
    }

    // 10. Compute instances
    let instances = compute_instances(&parsed);
    println!("  Instance 0 (poseidon): {}", hex::encode(instances[0].to_repr()));
    println!("  Instance 1 (final_root): {}", hex::encode(instances[1].to_repr()));

    println!("\n  All native checks passed!");
}


