fn test_debug_sku_commit() {
    let fixtures = discover_fixtures();
    if fixtures.is_empty() {
        return;
    }
    let json = load_fixture(&fixtures[0]);
    let parsed = parse_fixture(&json);

    // Extract sk_u_commit from child cell
    let child_data = &parsed.entries[1].cell_repr_data;
    let sk_u_commit_bytes: [u8; 32] = child_data[EVENT_SK_U_COMMIT_START..EVENT_SK_U_COMMIT_END]
        .try_into()
        .unwrap();
    let sk_u_commit_val = Fr::from_repr(sk_u_commit_bytes).unwrap();
    
    // Compute expected sk_u_commit = Poseidon(sk_u, 0)
    let expected_commit = poseidon_hash(&[parsed.sk_u, Fr::zero()]);
    
    println!("sk_u: {}", hex::encode(parsed.sk_u.to_repr()));
    println!("sk_u_commit from BOC: {}", hex::encode(sk_u_commit_val.to_repr()));
    println!("Poseidon(sk_u, 0):    {}", hex::encode(expected_commit.to_repr()));
    assert_eq!(sk_u_commit_val, expected_commit, "sk_u_commit mismatch!");
    println!("sk_u_commit check PASSED");
}


#[test]
fn test_debug_all_fixtures_sku_commit() {
    let fixtures = discover_fixtures();
    if fixtures.is_empty() {
        return;
    }

    let p_hex = "30644e72e131a029b85045b68181585d2833e84879b9709143e1f593f0000001";

    println!("Found {} fixtures", fixtures.len());
    for (idx, fixture_path) in fixtures.iter().enumerate() {
        let filename = fixture_path.file_name().unwrap().to_str().unwrap();
        println!("[{}] Processing: {}", idx, filename);
        let json = load_fixture(fixture_path);
        println!("[{}] Loaded OK", idx);
        let parsed = parse_fixture(&json);
        println!("[{}] Parsed OK", idx);
        
        let child_data = &parsed.entries[1].cell_repr_data;
        let sk_u_commit_bytes: [u8; 32] = child_data[EVENT_SK_U_COMMIT_START..EVENT_SK_U_COMMIT_END]
            .try_into()
            .unwrap();
        
        println!("[{}] {}: sk_u_commit_bytes = {}", idx, filename, hex::encode(&sk_u_commit_bytes));
        
        // Check if it's a valid Fr element
        let opt: Option<Fr> = Fr::from_repr(sk_u_commit_bytes).into();
        match opt {
            Some(fr) => {
                let expected = poseidon_hash(&[parsed.sk_u, Fr::zero()]);
                let match_str = if fr == expected { "MATCH" } else { "MISMATCH" };
                println!("[{}]   Valid Fr: {} ({})", idx, hex::encode(fr.to_repr()), match_str);
            },
            None => {
                println!("[{}]   NOT a valid Fr! (exceeds modulus)", idx);
                let fr = bytes_to_fr(&sk_u_commit_bytes);
                let expected = poseidon_hash(&[parsed.sk_u, Fr::zero()]);
                let match_str = if fr == expected { "MATCH" } else { "MISMATCH" };
                println!("[{}]   bytes_to_fr: {} ({})", idx, hex::encode(fr_to_bytes(fr)), match_str);
            }
        }
    }
    println!("Done with all fixtures");
}


