/// Regenerate tvm-sdk's halo2 test artifacts (proof + instances .bin files)
/// for the three H197 fixtures. Gated on env var `TVM_SDK_EXPORT_DIR`; inert by default.
///
/// Requires `PARAMS_DIR` to point at the directory containing the canonical
/// `kzg_bn254_19.srs` so that `gen_srs(K)` reads the SRS used to derive
/// `DARK_DEX_W8_VK_BYTES` in tvm-sdk.
///
/// Usage:
///   PARAMS_DIR=/path/to/tvm-sdk/tvm_vm/halo2_test_data \
///   TVM_SDK_EXPORT_DIR=/path/to/tvm-sdk/tvm_vm/halo2_test_data \
///   cargo test --release test_export_tvm_sdk_data -- --nocapture
///
/// Writes (for N ∈ {num_active_chain_steps} = {0, 1, 2}):
///   {TVM_SDK_EXPORT_DIR}/dark_dex_w8_L{N}_proof.bin
///   {TVM_SDK_EXPORT_DIR}/dark_dex_w8_L{N}_instances.bin   (5 × 32 bytes, LE Fr)
///
/// The live H626 fixture is skipped (different historical window).
#[test]
fn test_export_tvm_sdk_data() {
    use halo2_base::halo2_proofs::plonk::{keygen_pk, keygen_vk};
    use halo2_base::utils::fs::gen_srs;
    use halo2_base::utils::testing::{check_proof_with_instances, gen_proof_with_instances};

    let out_dir = match std::env::var("TVM_SDK_EXPORT_DIR") {
        Ok(p) => std::path::PathBuf::from(p),
        Err(_) => {
            println!("TVM_SDK_EXPORT_DIR not set — skipping.");
            return;
        }
    };
    assert!(out_dir.is_dir(), "TVM_SDK_EXPORT_DIR is not a directory: {}", out_dir.display());

    // Pick only H197 fixtures (the historical-window snapshot the tvm-sdk W=8 tests use).
    let h197: Vec<_> = discover_fixtures()
        .into_iter()
        .filter(|p| {
            p.file_name()
                .and_then(|n| n.to_str())
                .map(|n| n.contains("H197"))
                .unwrap_or(false)
        })
        .collect();
    assert_eq!(h197.len(), 3, "expected 3 H197 fixtures (L0/L1/L2), got {}", h197.len());

    let params = base_circuit_params();
    let ephemeral_pubkey = Fr::from(0xDEADu64);

    // Keygen against the first H197 fixture. VK is shape-only, fixture choice is moot.
    let kg_json = load_fixture(&h197[0]);
    let kg_parsed = parse_fixture(&kg_json);
    let kg_circuit = DarkDexCircuitNew::new(
        kg_parsed.sk_u,
        ephemeral_pubkey,
        kg_parsed.entries,
        kg_parsed.events_proof_siblings,
        kg_parsed.events_proof_position,
        kg_parsed.account_dapp_id,
        kg_parsed.account_id,
        kg_parsed.block_id,
        kg_parsed.envelope_hash_bytes,
        kg_parsed.block_proof_siblings,
        kg_parsed.block_proof_position,
        kg_parsed.dense_chain,
        kg_parsed.num_active_chain_steps,
        params.clone(),
    );

    println!("PARAMS_DIR = {:?}", std::env::var("PARAMS_DIR"));
    println!("Loading SRS (K={})...", K);
    let srs = gen_srs(K);
    let vk = keygen_vk(&srs, &kg_circuit).expect("keygen_vk failed");
    let pk = keygen_pk(&srs, vk, &kg_circuit).expect("keygen_pk failed");
    let break_points = kg_circuit.base_circuit_builder.borrow().break_points();

    for fixture in &h197 {
        let filename = fixture.file_name().unwrap().to_str().unwrap().to_string();
        let json = load_fixture(fixture);
        let parsed = parse_fixture(&json);
        let n_steps = parsed.num_active_chain_steps;
        assert!(n_steps <= 2, "unexpected chain step count {} for fixture {}", n_steps, filename);

        let mut instances = compute_instances(&parsed);
        instances.push(ephemeral_pubkey);
        assert_eq!(instances.len(), 5);

        let prover_circuit = DarkDexCircuitNew::new_for_proving(
            parsed.sk_u,
            ephemeral_pubkey,
            parsed.entries,
            parsed.events_proof_siblings,
            parsed.events_proof_position,
            parsed.account_dapp_id,
            parsed.account_id,
            parsed.block_id,
            parsed.envelope_hash_bytes,
            parsed.block_proof_siblings,
            parsed.block_proof_position,
            parsed.dense_chain,
            parsed.num_active_chain_steps,
            params.clone(),
            break_points.clone(),
        );

        println!("\n[{}] L{}: proving...", filename, n_steps);
        let proof_bytes = gen_proof_with_instances(&srs, &pk, prover_circuit, &[&instances]);
        println!("[{}] proof = {} bytes; sanity-verifying...", filename, proof_bytes.len());
        check_proof_with_instances(&srs, pk.get_vk(), &proof_bytes, &[&instances], true);

        // Serialize each Fr instance as 32 bytes LE (`Fr::to_repr()`), 5 × 32 = 160 B total.
        // The tvm-sdk verifier (`tvm_vm/src/executor/zk_halo2.rs:97-121`) decodes this via
        // `Fr::from_bytes_le()` on the non-u64-shaped path, which is byte-exact symmetric.
        let mut instances_bytes: Vec<u8> = Vec::with_capacity(5 * 32);
        for fr in &instances {
            instances_bytes.extend_from_slice(fr.to_repr().as_ref());
        }
        assert_eq!(instances_bytes.len(), 160);

        let proof_path = out_dir.join(format!("dark_dex_w8_L{}_proof.bin", n_steps));
        let instances_path = out_dir.join(format!("dark_dex_w8_L{}_instances.bin", n_steps));
        std::fs::write(&proof_path, &proof_bytes).expect("write proof");
        std::fs::write(&instances_path, &instances_bytes).expect("write instances");
        println!(
            "[{}] wrote {} ({} B) and {} ({} B)",
            filename,
            proof_path.display(),
            proof_bytes.len(),
            instances_path.display(),
            instances_bytes.len()
        );
    }

    println!("\nDone — wrote 3 fixtures to {}", out_dir.display());
}

